function detectNewsCatalyst(title) {
  const text = (title || "").toLowerCase();
  for (const cat of NEWS_CATALYST_CATEGORIES) {
    if (cat.keywords.some(kw => text.includes(kw))) return cat;
  }
  return { key: "others", label: "Others", color: "text-zinc-400 bg-zinc-700/40 border-zinc-600/40" };
}

// Sources that publish primarily opinion / editorial content — filtered out of the news feed
const OPINION_SOURCES = new Set([
  "seeking alpha", "seekingalpha", "the motley fool", "motley fool",
  "investorplace", "investor place", "zacks", "zacks.com",
  "thestreet", "the street", "investopedia", "kiplinger",
  "moneymorning", "money morning", "fool.com", "nasdaq.com",
  "24/7 wall st.", "24/7 wall st", "247wallst", "simply wall st",
  "wisesheets", "stockanalysis", "stock analysis",
]);

// Title patterns that signal opinion / listicle content rather than hard news
const OPINION_TITLE_PATTERNS = [
  /\bbetter buy\b/i,
  /\bbest stocks?\b/i,
  /\btop \d+ stocks?\b/i,
  /\b\d+ stocks? (to buy|to watch|to sell|you should)\b/i,
  /\bshould you buy\b/i,
  /\btime to buy\b/i,
  /\btime to sell\b/i,
  /\bis it time\b/i,
  /\bworth buying\b/i,
  /\bwhy (i|we) (own|bought|sold|like|think)\b/i,
  /\bhere'?s why\b/i,
  /\bwhy investors should\b/i,
  /\bmy (top|favorite|best)\b/i,
  /\b(buy|sell|hold) (or|vs\.?)\b/i,
  /\b(bull|bear) case\b/i,
  /\bprediction(s)? for\b/i,
  /\bforecast(s|ing)? for\b/i,
  /\bopinion\b/i,
];

function isOpinionPost(title, source) {
  const srcLower = (source || "").toLowerCase();
  if (OPINION_SOURCES.has(srcLower)) return true;
  // Partial match for sources (e.g. "Seeking Alpha - Premium")
  if ([...OPINION_SOURCES].some(s => srcLower.includes(s))) return true;
  return OPINION_TITLE_PATTERNS.some(re => re.test(title || ""));
}

// ---------------------------------------------------------------------------
// Per-filter column label for the Change% column
// ---------------------------------------------------------------------------

const CHANGE_COL_LABEL = {
  up4:     "1D Change%",
  dn4:     "1D Change%",
  up25q:   "Quarterly Change%",
  dn25q:   "Quarterly Change%",
  up25m:   "25% Monthly Change%",
  dn25m:   "25% Monthly Change%",
  up50m:   "50% Monthly Change%",
  dn50m:   "50% Monthly Change%",
  up13_34: "1.5M Change%",
  dn13_34: "1.5M Change%",
};

// Which field to read for the last (perf) column, keyed by scanner filter id.
// For 34D scanners: perf_34d is not yet in the schema; perf_1m is used as the
// closest approximation until breadth_stocks_builder.py provides perf_34d.
const PERF_FIELD = {
  up4:     "change_pct",
  dn4:     "change_pct",
  up25q:   "perf_3m",
  dn25q:   "perf_3m",
  up25m:   "perf_1m",
  dn25m:   "perf_1m",
  up50m:   "perf_1m",
  dn50m:   "perf_1m",
  up13_34: "perf_34d", // TODO: replace with dedicated field once schema has it
  dn13_34: "perf_34d",
};

// Client-side threshold guard for the last column.
// Only applied to up4/dn4 because change_pct comes directly from Finviz and
// is reliable. For quarterly/monthly/34D scanners, Finviz already pre-filters
// to the stated threshold using its own period calculation; our yfinance-based
// perf_1m/perf_3m/perf_34d uses a different lookback window and does not match
// closely enough to use as a hard filter without excluding valid stocks.
const PERF_THRESHOLD = {
  up4:  4,
  dn4: -4,
};

// Read a stock's perf value for the given field, with fallback for perf_34d.
function getPerfValue(s, field) {
  if (field === "perf_34d") {
    // perf_34d not yet available — fall back to perf_1m as approximation
    return s.perf_34d ?? s.perf_1m ?? null;
  }
  return s[field] ?? null;
}

// Parse dollar_volume which may arrive as a formatted string ("$1.2B") or number
function parseDollarVolume(v) {
  if (v == null) return null;
  if (typeof v === "number") return v;
  const s = String(v).replace(/[$,\s]/g, "");
  const m = s.match(/^([\d.]+)([KMBT]?)$/i);
  if (!m) return null;
  const mult = { K: 1e3, M: 1e6, B: 1e9, T: 1e12 }[m[2].toUpperCase()] ?? 1;
  return parseFloat(m[1]) * mult;
}

