// TradingView Financials widget — injected via script tag (iframe blocks financials pages)
const TradingViewFinancials = memo(function TradingViewFinancials({ ticker }) {
  const containerRef = useRef(null);

  useEffect(() => {
    if (!containerRef.current) return;
    containerRef.current.innerHTML = "";
    const widget = document.createElement("div");
    widget.className = "tradingview-widget-container__widget";
    widget.style.cssText = "height:100%;width:100%";
    containerRef.current.appendChild(widget);

    const script = document.createElement("script");
    script.type = "text/javascript";
    script.src = "https://s3.tradingview.com/external-embedding/embed-widget-financials.js";
    script.async = true;
    script.textContent = JSON.stringify({
      symbol: ticker,
      width: "100%",
      height: 830,
      locale: "en",
      colorTheme: "dark",
      isTransparent: false,
      displayMode: "regular",
    });
    containerRef.current.appendChild(script);

    return () => { if (containerRef.current) containerRef.current.innerHTML = ""; };
  }, [ticker]);

  return <div ref={containerRef} className="tradingview-widget-container h-full w-full" />;
});

const StockDetailModal = memo(function StockDetailModal({ stock, filter, onClose }) {
  const [tab, setTab] = useState("chart");
  const [news, setNews] = useState([]);
  const [newsLoading, setNewsLoading] = useState(true);
  const [newsError, setNewsError] = useState(null);

  const perfField      = PERF_FIELD[filter] ?? "change_pct";
  const changeColLabel = CHANGE_COL_LABEL[filter] ?? "Change%";
  const { ticker, company } = stock;
  const perfVal = getPerfValue(stock, perfField);

  // Fetch news EAGERLY on mount — Google News RSS (same source as gapper_service.py).
  // Company-specific: searches ticker + "stock" to filter market-relevant articles.
  useEffect(() => {
    setNewsLoading(true);
    setNewsError(null);
    setNews([]);
    const rss   = `https://news.google.com/rss/search?q=${encodeURIComponent(ticker + " stock")}&hl=en-US&gl=US&ceid=US:en`;
    const proxy = `https://corsproxy.io/?url=${encodeURIComponent(rss)}`;
    const ctrl  = new AbortController();
    fetch(proxy, { signal: ctrl.signal })
      .then((r) => r.text())
      .then((xml) => {
        const doc   = new DOMParser().parseFromString(xml, "text/xml");
        const items = Array.from(doc.querySelectorAll("item"))
          .map((el) => {
            const source = el.querySelector("source")?.textContent ?? "";
            const title  = el.querySelector("title")?.textContent ?? "";
            return {
              title,
              link:     el.querySelector("link")?.textContent ?? "",
              date:     el.querySelector("pubDate")?.textContent ?? "",
              source,
              catalyst: detectNewsCatalyst(title),
            };
          })
          .filter((item) => !isOpinionPost(item.title, item.source))
          .slice(0, 20);
        setNews(items);
        setNewsLoading(false);
      })
      .catch((e) => {
        if (e.name === "AbortError") return;
        setNewsError("Failed to load news.");
        setNewsLoading(false);
      });
    return () => ctrl.abort();
  }, [ticker]);

  // Escape closes only this panel (capture phase stops propagation to parent)
  useEffect(() => {
    const handler = (e) => { if (e.key === "Escape") { e.stopPropagation(); onClose(); } };
    window.addEventListener("keydown", handler, true);
    return () => window.removeEventListener("keydown", handler, true);
  }, [onClose]);

  // Compact scanner metrics shown above the TradingView fundamentals widget
  const scannerMetrics = [
    { label: "Price",        value: stock.price != null ? `$${stock.price.toFixed(2)}` : "—", cls: "text-zinc-200" },
    { label: "1D Chg",       value: fmtPct(stock.change_pct),  cls: changeCls(stock.change_pct)  },
    { label: "ADR%",         value: stock.adr_pct != null ? `${stock.adr_pct.toFixed(1)}%` : "—", cls: "text-zinc-200" },
    { label: "$ Vol",        value: stock.dollar_volume || "—", cls: "text-zinc-200" },
    { label: "Mkt Cap",      value: stock.market_cap_b != null ? `$${stock.market_cap_b.toFixed(1)}B` : "—", cls: "text-zinc-200" },
    { label: changeColLabel, value: fmtPct(perfVal),            cls: changeCls(perfVal)            },
    { label: "1M",           value: fmtPct(stock.perf_1m),     cls: changeCls(stock.perf_1m)      },
    { label: "3M",           value: fmtPct(stock.perf_3m),     cls: changeCls(stock.perf_3m)      },
  ];

  return (
    <div
      className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 backdrop-blur-sm"
      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
    >
      <div className="relative flex h-[82vh] w-full max-w-4xl flex-col rounded-xl border border-zinc-600 bg-zinc-950 shadow-2xl">

        {/* Header */}
        <div className="flex items-center gap-2 border-b border-zinc-800 px-4 py-2.5">
          <span className="font-mono text-base font-bold text-white">{ticker}</span>
          <span className="flex-1 truncate text-xs text-zinc-400">{company}</span>
          <a href={`https://finviz.com/quote.ashx?t=${ticker}`} target="_blank" rel="noopener noreferrer"
             title="Open in Finviz" className="text-zinc-500 hover:text-cyan-400 transition-colors">
            <ExternalLink className="h-3.5 w-3.5" />
          </a>
          <button onClick={onClose} className="rounded p-1 text-zinc-500 hover:bg-zinc-700 hover:text-zinc-200" aria-label="Close">
            <X className="h-4 w-4" />
          </button>
        </div>

        {/* Tab bar */}
        <div className="flex gap-1 border-b border-zinc-800 px-4">
          {["chart", "fundamentals", "news"].map((t) => (
            <button key={t} onClick={() => setTab(t)}
              className={`capitalize px-3 py-1.5 text-xs border-b-2 -mb-px transition-colors
                ${tab === t ? "border-cyan-400 text-cyan-400" : "border-transparent text-zinc-500 hover:text-zinc-300"}`}>
              {t}
            </button>
          ))}
        </div>

        {/* Tab body */}
        <div className="min-h-0 flex-1 flex flex-col">

          {tab === "chart" && (
            <iframe key={ticker} title={`${ticker} chart`}
              src={`https://www.tradingview.com/widgetembed/?symbol=${ticker}&interval=D&theme=dark&style=1&withdateranges=1&hide_legend=0&saveimage=1&hide_side_toolbar=0&allow_symbol_change=1`}
              className="w-full flex-1 border-0 rounded-b-xl" allowFullScreen />
          )}

          {tab === "fundamentals" && (
            <div className="flex flex-col flex-1 min-h-0">
              {/* Compact scanner metrics strip */}
              <div className="flex flex-wrap gap-x-4 gap-y-1 border-b border-zinc-800 px-4 py-2">
                {scannerMetrics.map(({ label, value, cls }) => (
                  <div key={label} className="flex items-baseline gap-1.5">
                    <span className="text-[10px] text-zinc-500 uppercase tracking-wide">{label}</span>
                    <span className={`font-mono text-xs font-semibold ${cls}`}>{value}</span>
                  </div>
                ))}
              </div>
              {/* TradingView Financials widget — fixed height, scrollable */}
              <div className="flex-1 overflow-y-auto">
                <TradingViewFinancials ticker={ticker} />
              </div>
            </div>
          )}

          {tab === "news" && (
            <div className="flex-1 overflow-y-auto p-3">
              {newsLoading ? (
                <div className="flex justify-center py-10">
                  <Loader2 className="h-5 w-5 animate-spin text-zinc-500" />
                </div>
              ) : newsError ? (
                <div className="py-10 text-center">
                  <p className="text-sm text-rose-400">{newsError}</p>
                  <a href={`https://news.google.com/search?q=${ticker}+stock`} target="_blank" rel="noopener noreferrer"
                     className="mt-2 block text-xs text-zinc-400 hover:text-cyan-400">
                    Search on Google News →
                  </a>
                </div>
              ) : news.length === 0 ? (
                <p className="py-10 text-center text-sm text-zinc-500">No recent news found.</p>
              ) : (
                <div className="space-y-1.5">
                  {news.map((item, i) => (
                    <a key={i} href={item.link} target="_blank" rel="noopener noreferrer"
                       className="flex items-start gap-2 rounded-lg bg-zinc-800/50 px-3 py-2 hover:bg-zinc-700/60 transition-colors">
                      {/* Left: headline + meta */}
                      <div className="flex-1 min-w-0">
                        <div className="text-xs leading-snug text-zinc-200">{item.title}</div>
                        <div className="mt-0.5 flex items-center gap-2">
                          {item.source && <span className="text-[10px] text-cyan-600">{item.source}</span>}
                          {item.date && (
                            <span className="text-[10px] text-zinc-500">
                              {new Date(item.date).toLocaleString("en-US", { month: "short", day: "numeric", hour: "2-digit", minute: "2-digit" })}
                            </span>
                          )}
                        </div>
                      </div>
                      {/* Right: catalyst tag */}
                      {item.catalyst && (
                        <span className={`shrink-0 self-center rounded border px-1.5 py-0.5 text-[10px] font-semibold leading-none ${item.catalyst.color}`}>
                          {item.catalyst.label}
                        </span>
                      )}
                    </a>
                  ))}
                </div>
              )}
            </div>
          )}

        </div>
      </div>
    </div>
  );
});

// ---------------------------------------------------------------------------
// List view — matches screenshot exactly: #, Ticker, Company, $Vol, ADR%, Change%
// ---------------------------------------------------------------------------

// Static column definitions for the first four sortable columns.
// The fifth (perf) column is built dynamically inside ListView using the filter prop.
const BASE_SORT_COLS = [
  { key: "ticker",        label: "Ticker",  align: "left",  numeric: false },
  { key: "company",       label: "Company", align: "left",  numeric: false },
  { key: "dollar_volume", label: "$ Vol",   align: "right", numeric: true  },
  { key: "adr_pct",       label: "ADR%",    align: "right", numeric: true  },
];

const ListView = memo(function ListView({ stocks, filter, onStockClick }) {
  const [sortKey, setSortKey] = useState(null);
  const [sortDir, setSortDir] = useState("asc");

  const changeColLabel = CHANGE_COL_LABEL[filter] ?? "Change%";
  const perfField = PERF_FIELD[filter] ?? "change_pct";

  // Build full column list with dynamic perf column appended
  const sortCols = [
    ...BASE_SORT_COLS,
    { key: perfField, label: null, align: "right", numeric: true },
  ];

  // Fixed handleSort — reads sortKey/sortDir directly from closure, no functional updater side-effects
  const handleSort = (key) => {
    if (sortKey === key) {
      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    } else {
      setSortKey(key);
      setSortDir("asc");
    }
  };

  const sortedStocks = useMemo(() => {
    if (!sortKey) return stocks;
    return [...stocks].sort((a, b) => {
      let av, bv;
      if (sortKey === "dollar_volume") {
        av = parseDollarVolume(a.dollar_volume);
        bv = parseDollarVolume(b.dollar_volume);
      } else if (sortKey === perfField) {
        av = getPerfValue(a, perfField);
        bv = getPerfValue(b, perfField);
      } else {
        av = a[sortKey];
        bv = b[sortKey];
      }
      // Nulls always last
      if (av == null && bv == null) return 0;
      if (av == null) return 1;
      if (bv == null) return -1;
      const cmp = typeof av === "string" ? av.localeCompare(bv) : av - bv;
      return sortDir === "asc" ? cmp : -cmp;
    });
  }, [stocks, sortKey, sortDir, perfField]);

  if (!stocks.length) {
    return <p className="py-12 text-center text-sm text-zinc-500">No stocks match the current filters.</p>;
  }

  const SortIcon = ({ colKey }) => {
    if (sortKey !== colKey) return <span className="ml-0.5 text-zinc-600">⇅</span>;
    return <span className="ml-0.5 text-white">{sortDir === "asc" ? "↑" : "↓"}</span>;
  };

  return (
    <div className="overflow-x-auto">
      <table className="w-full border-collapse text-left text-xs">
        <thead>
          <tr className="border-b border-zinc-800 text-zinc-500">
            <th className="w-8 py-2 pr-2 text-right font-medium">#</th>
            {sortCols.map((col) => {
              const label = col.key === perfField && col.label === null ? changeColLabel : col.label;
              return (
                <th
                  key={col.key}
                  onClick={() => handleSort(col.key)}
                  className={`px-2 py-2 font-medium cursor-pointer select-none hover:text-zinc-300 transition-colors
                    ${col.align === "right" ? "text-right" : ""}`}
                >
                  {label}<SortIcon colKey={col.key} />
                </th>
              );
            })}
          </tr>
        </thead>
        <tbody>
          {sortedStocks.map((s, i) => (
            <tr
              key={s.ticker}
              className="border-b border-zinc-800/50 hover:bg-zinc-800/30"
            >
              <td className="py-1.5 pr-2 text-right font-mono text-zinc-600">{i + 1}</td>
              <td className="px-2 py-1.5 font-mono font-semibold text-cyan-400">
                <button
                  onClick={() => onStockClick(s)}
                  className="hover:underline hover:text-white transition-colors"
                >
                  {s.ticker}
                </button>
              </td>
              <td className="max-w-[220px] truncate px-2 py-1.5 text-zinc-300">
                {s.company || "—"}
              </td>
              <td className="px-2 py-1.5 text-right font-mono text-zinc-400">
                {s.dollar_volume || "—"}
              </td>
              <td className="px-2 py-1.5 text-right font-mono text-zinc-300">
                {s.adr_pct != null ? `${s.adr_pct.toFixed(1)}%` : "—"}
              </td>
              <td className={`px-2 py-1.5 text-right font-mono font-semibold ${changeCls(getPerfValue(s, perfField))}`}>
                {fmtPct(getPerfValue(s, perfField))}
              </td>
            </tr>
          ))}
        </tbody>
        {/* Totals footer */}
        <tfoot>
          <tr className="border-t border-zinc-700 text-zinc-600 text-xs">
            <td colSpan={3} className="py-1.5 pr-2 text-right font-mono">
              {stocks.length} stocks
            </td>
            <td colSpan={3} />
          </tr>
        </tfoot>
      </table>
    </div>
  );
});

// ---------------------------------------------------------------------------
// Group view
// ---------------------------------------------------------------------------

function groupByIndustry(stocks) {
  const map = new Map();
  for (const s of stocks) {
    const key = s.industry || "Other";
    if (!map.has(key)) map.set(key, []);
    map.get(key).push(s);
  }
  return [...map.entries()]
    .map(([industry, items]) => ({ industry, items }))
    .sort((a, b) => b.items.length - a.items.length);
}

// GroupRow receives pre-sorted items and the active perf field from GroupView.
const GroupRow = memo(function GroupRow({ industry, items, perfField, onStockClick, cols, sortKey, sortDir, onSort }) {
  const [open, setOpen] = useState(false);
  const tickers = items.map((s) => s.ticker);

  const SortIcon = ({ colKey }) => {
    if (sortKey !== colKey) return <span className="ml-0.5 text-zinc-600">⇅</span>;
    return <span className="ml-0.5 text-white">{sortDir === "asc" ? "↑" : "↓"}</span>;
  };

  return (
    <div className="border-t border-zinc-800 first:border-t-0">
      {/* Industry header row */}
      <div
        className="group flex cursor-pointer items-center gap-2 px-3 py-2 hover:bg-zinc-800/40"
        onClick={() => setOpen((o) => !o)}
      >
        <span className="text-zinc-500 text-xs">{open ? "▾" : "▸"}</span>
        <span className="flex-1 text-sm font-medium text-zinc-200">{industry}</span>
        <span className="text-xs text-zinc-500">{items.length}</span>
        <span className="opacity-0 transition-opacity group-hover:opacity-100">
          <CopyButton tickers={tickers} />
        </span>
      </div>

      {open && (
        <div className="ml-4 border-l border-zinc-700 pb-1">
          {/* Column sort header — only shown when group is open */}
          <div className="flex items-center gap-3 border-b border-zinc-800 bg-zinc-900/80 px-3 py-1 text-xs font-medium text-zinc-500 sticky top-0 z-10">
            {cols.map((col) => (
              <button
                key={col.key}
                onClick={() => onSort(col.key)}
                className={`${col.cls} cursor-pointer select-none hover:text-zinc-300 transition-colors
                  ${col.align === "right" ? "text-right" : "text-left"}`}
              >
                {col.label}<SortIcon colKey={col.key} />
              </button>
            ))}
          </div>
          <div className="max-h-64 overflow-y-auto">
            {items.map((s) => {
              const perfVal = getPerfValue(s, perfField);
              return (
                <div
                  key={s.ticker}
                  className="flex items-center gap-3 px-3 py-1 text-xs hover:bg-zinc-800/30"
                >
                  <button
                    onClick={() => onStockClick(s)}
                    className="w-14 font-mono font-semibold text-cyan-400 hover:underline hover:text-white transition-colors text-left"
                  >
                    {s.ticker}
                  </button>
                  <span className="flex-1 truncate text-zinc-400">{s.company}</span>
                  <span className="w-12 text-right font-mono text-zinc-500">
                    {s.adr_pct != null ? `${s.adr_pct.toFixed(1)}%` : "—"}
                  </span>
                  <span className={`w-16 text-right font-mono font-semibold ${changeCls(perfVal)}`}>
                    {fmtPct(perfVal)}
                  </span>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
});

const GroupView = memo(function GroupView({ stocks, filter, onStockClick }) {
  const [sortKey, setSortKey] = useState(null);
  const [sortDir, setSortDir] = useState("asc");

  const perfField     = PERF_FIELD[filter] ?? "change_pct";
  const changeColLabel = CHANGE_COL_LABEL[filter] ?? "Change%";

  // Fixed handleSort — reads state from closure, no functional-updater side-effects
  const handleSort = (key) => {
    if (sortKey === key) {
      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    } else {
      setSortKey(key);
      setSortDir("asc");
    }
  };

  // Build groups then sort each group's items by the active column
  const groups = useMemo(() => {
    const raw = groupByIndustry(stocks);
    if (!sortKey) return raw;
    return raw.map((g) => ({
      ...g,
      items: [...g.items].sort((a, b) => {
        let av, bv;
        if (sortKey === perfField) {
          av = getPerfValue(a, perfField);
          bv = getPerfValue(b, perfField);
        } else if (sortKey === "adr_pct") {
          av = a.adr_pct;
          bv = b.adr_pct;
        } else {
          av = a[sortKey];
          bv = b[sortKey];
        }
        if (av == null && bv == null) return 0;
        if (av == null) return 1;
        if (bv == null) return -1;
        const cmp = typeof av === "string" ? av.localeCompare(bv) : av - bv;
        return sortDir === "asc" ? cmp : -cmp;
      }),
    }));
  }, [stocks, sortKey, sortDir, perfField]);

  if (!groups.length) {
    return <p className="py-12 text-center text-sm text-zinc-500">No groups to display.</p>;
  }

  // Column config for the stock-row header (mirrors the expanded row layout)
  const GROUP_STOCK_COLS = [
    { key: "ticker",   label: "Ticker",       align: "left",  cls: "w-14" },
    { key: "company",  label: "Company",       align: "left",  cls: "flex-1" },
    { key: "adr_pct",  label: "ADR%",          align: "right", cls: "w-12" },
    { key: perfField,  label: changeColLabel,  align: "right", cls: "w-16" },
  ];

  return (
    <div>
      {/* Industry / Count header */}
      <div className="flex items-center gap-2 border-b border-zinc-800 px-3 py-1.5 text-xs font-medium text-zinc-600">
        <span className="flex-1">Industry</span>
        <span>Count</span>
      </div>

      {groups.map((g) => (
        <GroupRow
          key={g.industry}
          industry={g.industry}
          items={g.items}
          perfField={perfField}
          onStockClick={onStockClick}
          cols={GROUP_STOCK_COLS}
          sortKey={sortKey}
          sortDir={sortDir}
          onSort={handleSort}
        />
      ))}
    </div>
  );
});

// ---------------------------------------------------------------------------
// Main modal
// ---------------------------------------------------------------------------

const BreadthStockModal = memo(function BreadthStockModal({ filter, filterLabel, onClose }) {
  const [view, setView] = useState("list");
  const [stocks, setStocks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedStock, setSelectedStock] = useState(null);
  const abortRef = useRef(null);

  const load = useCallback(async () => {
    setLoading(true);
    setError(null);
    abortRef.current?.abort();
    const ctrl = new AbortController();
    abortRef.current = ctrl;

    try {
      const res = await fetch(
        `${process.env.PUBLIC_URL}/breadth_stocks_${filter}.json?_=${Date.now()}`,
        { signal: ctrl.signal }
      );
      if (!res.ok) throw new Error(`HTTP ${res.status} — stock list not found. Run breadth_stocks_builder.py first.`);
      const data = await res.json();
      setStocks(data.stocks ?? []);
    } catch (e) {
      if (e.name === "AbortError") return;
      setError(e.message);
    } finally {
      setLoading(false);
    }
  }, [filter]);

  useEffect(() => {
    void load();
    return () => abortRef.current?.abort();
  }, [load]);

  // Close on Escape
  useEffect(() => {
    const handler = (e) => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [onClose]);

  // Client-side threshold guard: enforce each scanner's minimum perf cutoff
  // so edge-case entries from Finviz never slip through to the table.
  const displayStocks = useMemo(() => {
    const threshold = PERF_THRESHOLD[filter];
    if (threshold == null) return stocks;
    const field = PERF_FIELD[filter] ?? "change_pct";
    if (threshold > 0) {
      return stocks.filter((s) => (getPerfValue(s, field) ?? -Infinity) >= threshold);
    } else {
      return stocks.filter((s) => (getPerfValue(s, field) ?? Infinity) <= threshold);
    }
  }, [stocks, filter]);

  const allTickers = displayStocks.map((s) => s.ticker);

  return (
    <>
    {/* Backdrop */}
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm"
      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
    >
      {/* Panel */}
      <div className="relative flex h-[85vh] w-full max-w-3xl flex-col rounded-xl border border-zinc-700 bg-zinc-900 shadow-2xl">

        {/* Header */}
        <div className="flex items-center gap-3 border-b border-zinc-800 px-4 py-3">
          <div className="flex-1">
            <h2 className="text-sm font-semibold text-zinc-100">{filterLabel}</h2>
            {!loading && (
              <p className="text-xs text-zinc-500">
                {stocks.length} stocks · min $1B mkt cap
              </p>
            )}
          </div>

          {/* List / Group toggle */}
          <div className="flex items-center gap-1 rounded-lg border border-zinc-700 p-0.5">
            <button
              onClick={() => setView("list")}
              title="List view"
              className={`flex items-center gap-1.5 rounded-md px-2.5 py-1 text-xs transition-colors
                ${view === "list" ? "bg-zinc-700 text-zinc-100" : "text-zinc-400 hover:text-zinc-200"}`}
            >
              <LayoutList className="h-3.5 w-3.5" />
              List
            </button>
            <button
              onClick={() => setView("group")}
              title="Group by industry"
              className={`flex items-center gap-1.5 rounded-md px-2.5 py-1 text-xs transition-colors
                ${view === "group" ? "bg-zinc-700 text-zinc-100" : "text-zinc-400 hover:text-zinc-200"}`}
            >
              <Layers className="h-3.5 w-3.5" />
              Group
            </button>
          </div>

          {/* Copy all */}
          {allTickers.length > 0 && (
            <CopyButton tickers={allTickers} label="Copy" />
          )}

          {/* Close */}
          <button
            onClick={onClose}
            className="rounded p-1 text-zinc-500 hover:bg-zinc-700 hover:text-zinc-200"
            aria-label="Close"
          >
            <X className="h-4 w-4" />
          </button>
        </div>

        {/* Body */}
        <div className="min-h-0 flex-1 overflow-y-auto">
          {loading ? (
            <div className="flex h-full items-center justify-center">
              <Loader2 className="h-6 w-6 animate-spin text-zinc-500" />
            </div>
          ) : error ? (
            <div className="flex h-full flex-col items-center justify-center gap-2 text-sm text-rose-400 px-6 text-center">
              <p>{error}</p>
              <button
                onClick={() => void load()}
                className="mt-2 text-xs text-zinc-400 underline hover:text-zinc-200"
              >
                Retry
              </button>
            </div>
          ) : view === "list" ? (
            <ListView stocks={displayStocks} filter={filter} onStockClick={setSelectedStock} />
          ) : (
            <GroupView stocks={displayStocks} filter={filter} onStockClick={setSelectedStock} />
          )}
        </div>
      </div>
    </div>

    {/* Stock detail overlay — Chart / Fundamentals / News */}
    {selectedStock && (
      <StockDetailModal
        stock={selectedStock}
        filter={filter}
        onClose={() => setSelectedStock(null)}
      />
    )}
    </>
  );
});

export default BreadthStockModal;
